INSERT INTO [Orders] ([OrderDate], [OrderNumber], [ShippingAddress], [TotalPrice], [UserId])
OUTPUT INSERTED.[Id], INSERTED.[Status]
VALUES (@p0, @p1, @p2, @p3, @p4);

SET IMPLICIT_TRANSACTIONS OFF;
SET NOCOUNT ON;
MERGE [OrderItems] USING (
VALUES (@p5, @p6, @p7, @p8, @p9, 0),
(@p10, @p11, @p12, @p13, @p14, 1)) AS i ([OrderId], [ProductId], [ProductName], [Quantity], [UnitPrice], _Position) ON 1=0
WHEN NOT MATCHED THEN
INSERT ([OrderId], [ProductId], [ProductName], [Quantity], [UnitPrice])
VALUES (i.[OrderId], i.[ProductId], i.[ProductName], i.[Quantity], i.[UnitPrice])
OUTPUT INSERTED.[Id], i._Position;

SET IMPLICIT_TRANSACTIONS OFF;
SET NOCOUNT ON;
INSERT INTO [Orders] ([OrderDate], [OrderNumber], [ShippingAddress], [TotalPrice], [UserId])
OUTPUT INSERTED.[Id], INSERTED.[Status]
VALUES (@p0, @p1, @p2, @p3, @p4);
